#!/usr/bin/env python3
import os, base64

files = [
  ('app\\\\api\\\\cron\\\\personalkollen-sync\\\\route.ts', ''),
  ('app\\\\api\\\\chat\\\\route.ts', ''),
  ('vercel.json', ''),
]

for win_path, b64 in files:
    path = win_path.replace("\\\\", os.sep).replace("\\", os.sep)
    os.makedirs(os.path.dirname(path), exist_ok=True)
    with open(path, "wb") as f:
        f.write(base64.b64decode(b64))
    print(f"Written: {path}")
print("\nDone — git add . && git commit -m \"Wire Personalkollen to P&L, covers and AI\" && vercel --prod")
